"use strict";const e=require("../common/vendor.js"),n=require("../api/auth.js");exports.useAuth=function(){const o=e.ref(e.index.getStorageSync("token")||""),t=e.ref(e.index.getStorageSync("userInfo")||null),s=e.computed(()=>!!o.value);return{token:o,userInfo:t,isLoggedIn:s,checkLogin:()=>{o.value=e.index.getStorageSync("token")||"",t.value=e.index.getStorageSync("userInfo")||null},login:async()=>{try{const s=await new Promise((n,o)=>{e.index.login({provider:"weixin",success:n,fail:o})}),r=await n.wechatLogin(s.code);return o.value=r.token,t.value={id:r.userId,userType:"STUDENT"===r.userType?0:"TEACHER"===r.userType?1:2,userTypeText:r.userType},e.index.setStorageSync("token",r.token),e.index.setStorageSync("userInfo",t.value),r.isNewUser?e.index.showToast({title:"欢迎新用户",icon:"success"}):e.index.showToast({title:"登录成功",icon:"success"}),!0}catch(s){return console.error(s),e.index.showToast({title:"登录失败",icon:"none"}),!1}},logout:()=>{e.index.removeStorageSync("token"),e.index.removeStorageSync("userInfo"),o.value="",t.value=null,e.index.showToast({title:"已退出",icon:"success"})}}},exports.useUserType=function(){const e={0:"学生",1:"教师",2:"教职工"},n={STUDENT:0,TEACHER:1,STAFF:2};return{getUserTypeName:n=>e[n]||"用户",getUserTypeCode:e=>n[e]??0}};
